import React from 'react';

function GrafanaPanel() {
  // Grafana dashboard URL - localhost:3000 je default Grafana port
  // Možeš promijeniti dashboard UID ako imaš specifičan dashboard
  const grafanaUrl = 'http://localhost:3000/d/iot-dashboard/iot-dashboard?orgId=1&refresh=5s&kiosk';

  return (
    <div>
      <iframe
        className="grafana-frame"
        src={grafanaUrl}
        title="Grafana Dashboard"
        frameBorder="0"
        allowFullScreen
      />
      <div style={{ marginTop: '10px', fontSize: '0.85rem', color: 'rgba(255,255,255,0.7)' }}>
        <p>ℹ️ Grafana Dashboard prikazuje podatke sa svih senzora u realnom vremenu.</p>
        <p>Za direktan pristup: <a href="http://localhost:3000" target="_blank" rel="noopener noreferrer" style={{ color: '#3498db' }}>http://localhost:3000</a></p>
        <p>Login: admin / admin_password</p>
      </div>
    </div>
  );
}

export default GrafanaPanel;
